int findMaxContentChildren(long long children[], int n,
                           long long cookies[], int m) {
    qsort(children, n, sizeof(long long), cmp);
    qsort(cookies, m, sizeof(long long), cmp);

    int i = 0, j = 0, cnt = 0;
    while (i < n && j < m) {
        if (cookies[j] >= children[i]) {
            cnt++;
            i++;
            j++;
        } else {
            j++;
        }
    }
    return cnt;
}

code.Java:
static int findMaxContentChildren(List<Long> children, List<Long> cookies) {
    Collections.sort(children);
    Collections.sort(cookies);

    int i = 0, j = 0, cnt = 0;
    while (i < children.size() && j < cookies.size()) {
        if (cookies.get(j) >= children.get(i)) {
            cnt++;
            i++;
            j++;
        } else {
            j++;
        }
    }
    return cnt;
}

